import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

const RegulatoryManager = () => {
  const { user } = useAuth();
  const { disciplineTypes, addDisciplineType, removeDisciplineType } = useData();
  const [newRule, setNewRule] = useState({ name: '', level: 'Nhẹ' });

  // Kiểm tra quyền: Chỉ Reg Admin hoặc Chief Admin
  const canManageRules = user?.role === 'reg_admin' || user?.role === 'chief_admin';

  const handleAdd = (e) => {
    e.preventDefault();
    if (!newRule.name) return;
    addDisciplineType(newRule.name, newRule.level);
    setNewRule({ name: '', level: 'Nhẹ' });
  };

  if (!canManageRules) {
    return <div style={{ padding: '20px', color: 'red' }}>⛔ Bạn không có quyền truy cập trang Quản lý Quy chế!</div>;
  }

  return (
    <div>
      <h2>Ban hành Quy định & Kỷ luật</h2>
      <p>Dành cho <strong>Regulatory Administrator</strong> thiết lập các hình thức kỷ luật để Op Admin sử dụng khi giao việc.</p>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '30px' }}>
        {/* Form Ban hành */}
        <div style={{ background: 'white', padding: '20px', borderRadius: '8px', border: '1px solid #ddd', height: 'fit-content' }}>
            <h4 style={{ marginTop: 0, color: '#003366' }}>Ban hành hình thức kỷ luật mới</h4>
            <form onSubmit={handleAdd}>
                <label style={{ display: 'block', marginBottom: '5px' }}>Tên hình thức / Nội dung:</label>
                <input 
                    value={newRule.name} 
                    onChange={e => setNewRule({...newRule, name: e.target.value})}
                    placeholder="VD: Trừ 50% thưởng tháng..."
                    style={{ width: '100%', padding: '10px', marginBottom: '15px', boxSizing: 'border-box' }}
                    required
                />
                
                <label style={{ display: 'block', marginBottom: '5px' }}>Mức độ:</label>
                <select 
                    value={newRule.level}
                    onChange={e => setNewRule({...newRule, level: e.target.value})}
                    style={{ width: '100%', padding: '10px', marginBottom: '15px', boxSizing: 'border-box' }}
                >
                    <option value="Nhẹ">🟢 Nhẹ</option>
                    <option value="Trung bình">🟡 Trung bình</option>
                    <option value="Nặng">🔴 Nặng</option>
                    <option value="Nghiêm trọng">⚫ Nghiêm trọng</option>
                </select>

                <button type="submit" style={{ width: '100%', background: '#003366', color: 'white', padding: '10px', border: 'none', borderRadius: '4px', cursor: 'pointer', fontWeight: 'bold' }}>
                    BAN HÀNH
                </button>
            </form>
        </div>

        {/* Danh sách đang áp dụng */}
        <div>
            <h4 style={{ marginTop: 0 }}>Danh sách hình thức kỷ luật đang áp dụng</h4>
            <ul style={{ listStyle: 'none', padding: 0 }}>
                {disciplineTypes.map(d => (
                    <li key={d.id} style={{ background: 'white', borderBottom: '1px solid #eee', padding: '15px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div>
                            <strong>{d.name}</strong>
                            <div style={{ fontSize: '0.85rem', color: '#666', marginTop: '5px' }}>Mức độ: {d.level}</div>
                        </div>
                        <button 
                            onClick={() => removeDisciplineType(d.id)}
                            style={{ background: '#ffccc7', color: '#cf1322', border: 'none', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}
                        >
                            Hủy bỏ
                        </button>
                    </li>
                ))}
            </ul>
        </div>
      </div>
    </div>
  );
};

export default RegulatoryManager;
